    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Soccer Conditioning - 4w 4x/wk',
    'sport_specific',
    4,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Soccer Conditioning'
ON CONFLICT DO NOTHING;

