ts": 6, "reps": 30, "rest_seconds": 60, "weight_guidance": "30-meter sprints at 90-95% effort", "equipment": "None", "body_part": "Full Body", "primary_muscle": "Quadriceps", "secondary_muscles": ["Hamstrings", "Calves", "Glutes"], "difficulty": "intermediate", "form_cue": "Explosive start, drive arms, high knees", "substitution": "Treadmill Sprints", "exercise_library_id": null, "in_library": false}, {"name": "Bounding", "sets": 3, "reps": 8, "rest_seconds": 45, "weight_guidance": "Exaggerated running strides", "equipment": "None", "body_part": "Legs", "primary_muscle": "Glutes", "secondary_muscles": ["Quadriceps", "Calves", "Core"], "difficulty": "intermediate", "form_cue": "Long strides, drive knee high, swing arms", "substitution": "Broad Jumps", "exercise_library_id": null, "in_library": false}, {"name": "Deceleration Drills", "sets": 4, "reps": 1, "rest_seconds": 30, "weight_guidance": "Sprint 20m, decelerate in 5m", "equipment": "None", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Hamstrings", "Core"], "difficulty": "intermediate", "form_cue": "Lower center of gravity, chop steps to stop", "substitution": "Backpedal Sprints", "exercise_library_id": null, "in_library": false}]}, {"workout_name": "Day 3 - Lower Body Strength", "type": "strength", "duration_minutes": 50, "exercises": [{"name": "Barbell Back Squat", "sets": 4, "reps": 6, "rest_seconds": 120, "weight_guidance": "Heavy - RPE 8, build leg power", "equipment": "Barbell", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Glutes", "Hamstrings", "Core"], "difficulty": "intermediate", "form_cue": "Below parallel, drive through heels", "substitution": "Front Squat", "exercise_library_id": null, "in_library": false}, {"name": "Romanian Deadlift", "sets": 4, "reps": 8, "rest_seconds": 90, "weight_guidance": "Heavy - hamstring injury prevention", "equipment": "Barbell", "body_part": "Legs", "primary_muscle": "Hamstrings", "secondary_muscles": ["Glutes"