x, max height", "equipment": "Plyo Box", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Glutes", "Calves"], "difficulty": "intermediate", "form_cue": "Reset each rep, maximum height", "substitution": "Jump Squats", "exercise_library_id": null, "in_library": false}, {"name": "Broad Jumps", "sets": 4, "reps": 5, "rest_seconds": 60, "weight_guidance": "Max distance each rep", "equipment": "None", "body_part": "Legs", "primary_muscle": "Glutes", "secondary_muscles": ["Quadriceps", "Hamstrings"], "difficulty": "intermediate", "form_cue": "Arm swing, drive forward, stick landing", "substitution": "Tuck Jumps", "exercise_library_id": null, "in_library": false}, {"name": "Medicine Ball Rotational Throw", "sets": 3, "reps": 8, "rest_seconds": 45, "weight_guidance": "8-12 lb ball, throw against wall", "equipment": "Medicine Ball", "body_part": "Core", "primary_muscle": "Obliques", "secondary_muscles": ["Core", "Hips"], "difficulty": "intermediate", "form_cue": "Rotate from hips, release at hip height", "substitution": "Cable Woodchops", "exercise_library_id": null, "in_library": false}, {"name": "Single Leg Hop (Bounding)", "sets": 3, "reps": 8, "rest_seconds": 45, "weight_guidance": "Hop forward on one leg", "equipment": "None", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Glutes", "Calves", "Core"], "difficulty": "intermediate", "form_cue": "Drive knee, land softly on same leg", "substitution": "Walking Lunges", "exercise_library_id": null, "in_library": false}, {"name": "Hang Clean", "sets": 4, "reps": 5, "rest_seconds": 75, "weight_guidance": "Moderate barbell", "equipment": "Barbell", "body_part": "Full Body", "primary_muscle": "Glutes", "secondary_muscles": ["Hamstrings", "Traps", "Shoulders"], "difficulty": "advanced", "form_cue": "Explosive hip extension, catch in front rack", "substitution": "Kettlebell Swings", "exercise_library_id": null, "in_library": false}, {"name": "Anti-Rotation Press", "sets": 3, "re